    string resultingString(string s) {
        int n = s.length();
        for (int i = 0; i < n - 1; i++) {
            if (s[i] == s[i + 1] && isalpha(s[i]) && isalpha(s[i + 1])) {
                swap(s[i], s[i + 1]);
                n--;
            }
        }
        return s;
